// T[] means 'array of T' -- here T is number
let scores: number[] = [85, 92, 78];

// Array<T> is the equivalent generic syntax
let names: Array<string> = ['Alice', 'Bob'];

// for...of gives you each element directly (not the index)
const fruits = ['Apple', 'Banana', 'Cherry'];

for (const fruit of fruits) {
  console.log(fruit); // logs each fruit string
}

// .map creates a new array with each element transformed
const numbers = [1, 2, 3, 4];

const doubled = numbers.map(n => n * 2);
// doubled is [2, 4, 6, 8] -- original stays unchanged

// .filter keeps elements where the callback returns true
const ages = [12, 18, 25, 30, 15];

const adults = ages.filter(age => age >= 18);
// adults is [18, 25, 30] -- minors are removed

// .reduce folds the array into one value
const prices = [10, 20, 30];

// sum starts at 0, each price is added in sequence
const total = prices.reduce((sum, price) => sum + price, 0);
// total is 60

// .find returns the first element where callback is true
const users = [
  { id: 1, name: 'Alice' },
  { id: 2, name: 'Bob' }
];

const user = users.find(u => u.id === 2);
// user is { id: 2, name: 'Bob' } -- stops at first match
